mapper.select:
SELECT D.DETAIL_ID, D.TARGET_ID, T.NAME AS HOST_NAME, D.HASH_ID, D.AP_NO, D.FID, D.ORIGINAL_PATH, D.NEW_PATH, D.STATUS, D.ERROR_MESSAGE, D.USER_NO, U.USER_NAME, D.ACTION, CASE D.ACTION WHEN 'quarantine' THEN '파일이동' WHEN 'delete' THEN '삭제' WHEN 'encrypt' THEN '암호화' ELSE D.ACTION END AS ACTION_KR, D.PASSWORD, D.REASON, DATE_FORMAT(D.REGDATE, '%Y-%m-%d %H:%i:%s') AS REQUEST_DATE, DATE_FORMAT(D.PROCESS_DATE, '%Y-%m-%d %H:%i:%s') AS PROCESS_DATE FROM PI_REMEDIATION_DETAIL D LEFT JOIN pi_user U ON D.USER_NO = U.USER_NO LEFT JOIN pi_targets T ON D.TARGET_ID = T.TARGET_ID AND D.AP_NO = T.AP_NO WHERE 1=1
AND D.TARGET_ID IN
#{targetId}
AND D.ACTION = #{action}
AND T.NAME LIKE CONCAT('%', #{target_name}, '%')
AND U.USER_NAME LIKE CONCAT('%', #{user_name}, '%')
AND D.STATUS = #{status}
AND DATE_FORMAT(D.REQUEST_DATE, '%Y-%m-%d') >= #{fromDate}
AND DATE_FORMAT(D.REQUEST_DATE, '%Y-%m-%d') <= #{toDate}
ORDER BY D.DETAIL_ID DESC

SELECT TARGET_ID
FROM pi_target_user
WHERE USER_NO = #{user_no}
